	for (j = n; j; --j)
		if (a[j] < 0) x[++t] = -a[j];
		else if (a[j] != x[t]) x[++t] = a[j], a[j] = -a[j];
		else --t;
	if (t) puts("NO");
	else {
		puts("YES");
		for (i = 1; i <= n; ++i) printf("%d ", a[i]);
	}
	return 0;
}

