{
    scanf("%d%d\n",&n,&m);
    for(i=1;i<=n;i++)
    {
        scanf("%s",&a);
        for(j=0;j<m;j++)
        {
            if(a[j]=='E')
            {
                t1=i;
                t2=j;
            }
            if(a[j]=='S')
            {
                s1=i;
                s2=j;
                can[i][j]=true;
            }
            if((a[j]>='0')&&(a[j]<='9'))
            {
                can[i][j]=true;
                di[i][j]=a[j]-'0';
            }
        }
    }

    return 0;
