{
	int n,m,x,y,i,j;
	scanf("%d %d",&n,&m);
	for(i=0;i<n-1;i++){
		scanf("%d %d",&x,&y);
		ins(x-1,y-1);
		ins(y-1,x-1);
	}
	dfs1(0,0,1);
	for(i=1;i<20;i++)
		for(j=0;j<n;j++)
			par[i][j]=par[i-1][par[i-1][j]];
	brek(0,-1);
	for(i=0;i<n;i++)
		ans[i]=1000000001;
	upd(0);
	while(m--){
		scanf("%d %d",&x,&y);
		if(x==1) upd(y-1);
		else printf("%d\n",query(y-1));
	}
}

