	int64 carry = 10;
	if (n == 0){
		printf("0");
		return;
	}
	if (n < 0){
		printf("-");
		n *= -1;
	}
	char buf[20];
	buf[0] = '\0';
	int i = 0, j;
	while (n > 0){
		buf[i] = n % carry;
		n = n / carry;
		i += 1;
	}
	i--;
	for (j = i; j>= 0; j--){
		printf("%c", 48 + buf[j]);
	}
}
void uint64_print(uint64 n){
	uint64 carry = 10;
	if (n == 0){
		printf("0");
		return;
	}
	char buf[20];
	buf[0] = '\0';
	int i = 0, j;
	while (n != 0){
		buf[i] = n % carry;
		n = n / carry;
		i += 1;
	}
	i--;
	for (j = i; j>= 0; j--){
		printf("%c", 48 + buf[j]);
	}
}


