        h[i] = a[i] = 0;
    for (i = 0; i < n; i++)
        {
        if (scanf("%hu %2s %hu %2s",&t,wt,&m,cd) != 4)
            return -1;
        if (t < 1 || t > 90)
            return -1;
        if (i && t <= tp)
            return -1;
        tp = t;
        if (m < 1 || m > 99)
            return -1;
        if (strlen(wt) != 1 || strlen(cd) != 1)
            return -1;
        if ((wt[0] != 'h' && wt[0] != 'a') || (cd[0] != 'y' && cd[0] != 'r'))
            return -1;
        p = (wt[0] == 'h' ? h : a);
        if (cd[0] == 'y' && !p[m-1])
            p[m-1] = 1;
        else if (p[m-1] != 2)
            {
            p[m-1] = 2;
            printf ("%s %hu %hu\n",(wt[0] == 'h' ? tmh : tma),m,t);
            }
        }
    return 0;
    }

