void sort(long long * a, long long * b) {
  if (a + 1 >= b) return;
  long long * i = a;
  long long * j = b - 1;
  long long x = a[(b - a) * 2 / 7];
  while (i <= j) {
    while (*i < x) ++i;
    while (*j > x) --j;
    if (i <= j) {    
      long long tmp = *i;
      *i = *j;
      *j = tmp;
      ++i;
      --j;
    }
  }
  sort(a, j + 1);
  sort(i, b);
}

