void quicksort(point arr[], int beg, int end)
{
  if (end > beg + 1)
  {
    int piv = (arr+beg) -> left, l = beg + 1, r = end;
    while (l < r)
    {
      if ((arr+l)->left <= piv)
        l++;
      else
        swap(&arr[l], &arr[--r]);
    }
    swap(&arr[--l], &arr[beg]);
    quicksort(arr, beg, l);
    quicksort(arr, r, end);
  }
}

void swap(point *a, point *b)
{
	    point temp = *a;
	    *a = *b;
	    *b = temp;
}

