	int n, i, j, count=0;
	char a[200], b[200];

	scanf("%d\n", &n);
	scanf("%s", a);

	for (i=0; i<n; i++)
		for (j=i; j<n; j++){
			copy(a,i,j,b);
			if (ok(b)==1){
				count++;
			}
			memset(b,0,sizeof(b));
		}
	printf("%d", count);

	return 0;
}

